import { readFileSync, writeFileSync } from "node:fs";
import { resolve } from "node:path";

const REPO_ROOT = resolve(import.meta.dirname, "..");
const TEMPLATE_DIR = resolve(REPO_ROOT, ".github", "ISSUE_TEMPLATE");
const PUBLISH_TEMPLATE_PATH = resolve(TEMPLATE_DIR, "publish-map.yml");
const UPDATE_TEMPLATE_PATH = resolve(TEMPLATE_DIR, "update-map.yml");
const GENERATED_HEADER =
  "# AUTO-GENERATED by scripts/generate-map-templates.mjs. Do not edit directly.";

function markdown(value) {
  return {
    type: "markdown",
    attributes: { value },
  };
}

function input(id, label, description, opts = {}) {
  const item = {
    type: "input",
    id,
    attributes: { label, description },
  };
  if (opts.placeholder !== undefined) item.attributes.placeholder = opts.placeholder;
  if (opts.value !== undefined) item.attributes.value = opts.value;
  if (opts.required !== undefined) item.validations = { required: opts.required };
  return item;
}

function textarea(id, label, description, opts = {}) {
  const item = {
    type: "textarea",
    id,
    attributes: { label, description },
  };
  if (opts.render !== undefined) item.attributes.render = opts.render;
  if (opts.placeholder !== undefined) item.attributes.placeholder = opts.placeholder;
  if (opts.required !== undefined) item.validations = { required: opts.required };
  return item;
}

function checkboxes(id, label, description, options) {
  return {
    type: "checkboxes",
    id,
    attributes: {
      label,
      description,
      options: options.map((entry) =>
        typeof entry === "string" ? { label: entry } : entry
      ),
    },
  };
}

function dropdown(id, label, description, options, required) {
  return {
    type: "dropdown",
    id,
    attributes: {
      label,
      description,
      options,
    },
    validations: {
      required,
    },
  };
}

function mapIdField(description) {
  return input("map-id", "Map ID", description, {
    placeholder: "raleigh",
    required: true,
  });
}

