function toYamlScalar(value) {
  if (typeof value === "number" || typeof value === "boolean") return String(value);
  if (value === null) return "null";
  if (typeof value === "string") return JSON.stringify(value);
  throw new Error(`Unsupported scalar type: ${typeof value}`);
}

function isObject(value) {
  return value !== null && typeof value === "object" && !Array.isArray(value);
}

function renderObjectLines(value, indent, firstLinePrefix = "") {
  const isArrayItemObject = firstLinePrefix.length > 0;
  return Object.entries(value).flatMap(([key, entry], index) => {
    const isFirst = index === 0;
    const keyIndent = isArrayItemObject && !isFirst ? indent + 2 : indent;
    const spacing = " ".repeat(keyIndent);
    const keyPrefix = isFirst && firstLinePrefix ? `${spacing}${firstLinePrefix}${key}` : `${spacing}${key}`;

    if (typeof entry === "string" && entry.includes("\n")) {
      const block = entry
        .split("\n")
        .map((line) => `${" ".repeat(keyIndent + 2)}${line}`);
      return [`${keyPrefix}: |`, ...block];
    }

    if (isObject(entry) || Array.isArray(entry)) {
      return [`${keyPrefix}:`, renderYaml(entry, keyIndent + 2)];
    }

    return [`${keyPrefix}: ${toYamlScalar(entry)}`];
  });
}

function renderYaml(value, indent = 0) {
  const spacing = " ".repeat(indent);

  if (Array.isArray(value)) {
    return value
      .map((item) => {
        if (isObject(item)) {
          return renderObjectLines(item, indent, "- ").join("\n");
        }
        if (Array.isArray(item)) {
          return `${spacing}-\n${renderYaml(item, indent + 2)}`;
        }
        return `${spacing}- ${toYamlScalar(item)}`;
      })
      .join("\n");
  }

  if (isObject(value)) {
    return renderObjectLines(value, indent).join("\n");
  }

  return `${spacing}${toYamlScalar(value)}`;
}

function normalizeNewlines(content) {
  return content.replace(/\r\n/g, "\n");
}

function buildTemplateFile(doc) {
  return `${GENERATED_HEADER}\n${renderYaml(doc)}\n`;
}

function verifySharedTail() {
  const publishTail = JSON.stringify(publishTemplateDoc.body.slice(2));
  const updateTail = JSON.stringify(updateTemplateDoc.body.slice(2));
  if (publishTail !== updateTail) {
    throw new Error("Template bodies after map-id must remain identical.");
  }
}

function fileMatches(path, content) {
  const current = normalizeNewlines(readFileSync(path, "utf-8"));
  return current === content;
}

function main() {
  verifySharedTail();

  const publishContent = buildTemplateFile(publishTemplateDoc);
  const updateContent = buildTemplateFile(updateTemplateDoc);
  const isCheckMode = process.argv.includes("--check");

  if (isCheckMode) {
    const publishMatches = fileMatches(PUBLISH_TEMPLATE_PATH, publishContent);
    const updateMatches = fileMatches(UPDATE_TEMPLATE_PATH, updateContent);
    if (!publishMatches || !updateMatches) {
      console.error("Map issue templates are out of date.");
      console.error("Run: node scripts/generate-map-templates.mjs");
      process.exit(1);
    }
    console.log("Map issue templates are in sync.");
    return;
  }

  writeFileSync(PUBLISH_TEMPLATE_PATH, publishContent);
  writeFileSync(UPDATE_TEMPLATE_PATH, updateContent);
  console.log("Generated publish-map.yml and update-map.yml");
}

main();
